sys_script.script:
(function executeRule(current, previous) {

    if (!current.fiscal_year)
        return;

    // Map fiscal_period_sys_id → quota_period_sys_id
    var fiscalToQuotaMap = {};

    // Helper to create quota periods for a given period type
    function createQuotaPeriods(periodType) {

        var fp = new GlideRecord('x_ctans_incentnow_fiscal_period');
        fp.addQuery('fiscal_year', current.fiscal_year);
        fp.addQuery('period_type', periodType);
        fp.orderBy('period_number');
        fp.query();

        while (fp.next()) {

            var qp = new GlideRecord('x_ctans_incentnow_quota_period');
            qp.initialize();
            qp.quota = current.sys_id;
            qp.fiscal_period = fp.sys_id;
            qp.period_type = fp.period_type;
            qp.period_number = fp.period_number;
            qp.target_value = 0;
			qp.calculation_mode = 'driven_by_annual_quota';


            if (fp.parent_period) {
                var parentQuotaSysId = fiscalToQuotaMap[fp.parent_period.toString()];
                if (parentQuotaSysId) {
                    qp.parent_period = parentQuotaSysId;
                }
            }

            var qpSysId = qp.insert();

            // Store mapping
            fiscalToQuotaMap[fp.sys_id.toString()] = qpSysId;
        }
    }

    // ---------- Explicit hierarchy order ----------
    createQuotaPeriods('year');
    createQuotaPeriods('quarter');
    createQuotaPeriods('month');

})(current, previous);
